INSERT [dbo].[sga_programa]  VALUES ( N'Maestría en Ciencias y Tecnologías de Seguridad', 0, N'El Instituto Nacional de Astrofísica, Óptica y Electrónica (INAOE), considerando las demandas actuales en materia de seguridad informática, creó en 2018 la Maestría en Ciencias y Tecnologías de Seguridad (MCTS). La maestría está fundamentada en cuatro líneas de generación y aplicación del conocimiento: L1: Ocultamiento y Protección de Datos, L2: Seguridad en Sistemas Embebidos, L3: Estrategias de prevención y reacción ante ataques cibernéticos y L4: Sistemas Inteligentes para Aplicaciones de Seguridad, su Normatividad y Políticas Públicas. De esta forma la MCTS participa en la formación del capital humano necesario para mitigar los riesgos de ciberseguridad a los que la sociedad está expuesta debido a la creciente adopción y penetración de las tecnologías de la información y las comunicaciones en la vida cotidiana.', CAST(N'2025-06-04T11:32:36.420' AS DateTime), NULL, N'Maestro en Ciencias y Tecnologías de Seguridad', 0, 8, 8, NULL, NULL, 0, NULL, NULL, N'656543', N'S-JG-O-II-2017-11 ', NULL, NULL, NULL, NULL)



